    else if (addonly)
        s->kind = SC_ADDTABLE;
    else if (rename)
        s->kind = SC_RENAMETABLE;
    else if (fulluprecs)
        s->kind = SC_FULLUPRECS;
    else if (partialuprecs)
        s->kind = SC_PARTIALUPRECS;
    else if (is_trigger && addonly)
        s->kind = SC_ADD_TRIGGER;
    else if (is_trigger && drop_table)
        s->kind = SC_DEL_TRIGGER;
    else if (drop_table)
        s->kind = SC_DROPTABLE;
    else if (addsp)
        s->kind = SC_ADDSP;
    else if (delsp)
